import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";

function Reports() {
  const [reports, setReports] = useState([]);
  const [users, setUsers] = useState([]);
  const [classes, setClasses] = useState([]);
  const [courses, setCourses] = useState([]);
  const [tests, setTests] = useState([]);
  const [classPerformance, setClassPerformance] = useState([]);
  const [teacherActivity, setTeacherActivity] = useState([]);
  const user = useSelector((state) => state.auth.user);

  useEffect(() => {
    fetch("http://localhost:3001/reports")
      .then((res) => res.json())
      .then((data) => setReports(data));
    fetch("http://localhost:3001/users")
      .then((res) => res.json())
      .then((data) => setUsers(data));
    fetch("http://localhost:3001/classes")
      .then((res) => res.json())
      .then((data) => setClasses(data));
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(data));
    fetch("http://localhost:3001/tests")
      .then((res) => res.json())
      .then((data) => setTests(data));
  }, []);

  useEffect(() => {
    // Calculate class performance
    const performance = classes.map((cls) => {
      const classStudents = users.filter(
        (u) => u.role === "student" && u.classId === cls.id
      );
      const classGrades = reports
        .filter((r) => r.type === "student_performance" && classStudents.some((s) => s.id === r.data.studentId))
        .map((r) => r.data.score);
      const averageScore = classGrades.length
        ? (classGrades.reduce((sum, score) => sum + score, 0) / classGrades.length).toFixed(2)
        : "Нет данных";
      return { className: cls.name, averageScore };
    });
    setClassPerformance(performance);

    // Calculate teacher activity
    const activity = users
      .filter((u) => u.role === "teacher")
      .map((teacher) => {
        const teacherCourses = courses.filter((c) => c.teacherId === teacher.id);
        const teacherTests = tests.filter((t) => teacherCourses.some((c) => c.id === t.courseId));
        return {
          teacherName: teacher.name,
          courseCount: teacherCourses.length,
          testCount: teacherTests.length,
        };
      });
    setTeacherActivity(activity);
  }, [users, classes, courses, tests, reports]);

  if (user?.role !== "admin") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Отчеты</h1>
      <h3>Успеваемость классов</h3>
      <ul className="list-group mb-4">
        {classPerformance.map((perf, index) => (
          <li key={index} className="list-group-item">
            <strong>Класс:</strong> {perf.className} | <strong>Средний балл:</strong> {perf.averageScore}
          </li>
        ))}
      </ul>
      <h3>Активность преподавателей</h3>
      <ul className="list-group mb-4">
        {teacherActivity.map((activity, index) => (
          <li key={index} className="list-group-item">
            <strong>Преподаватель:</strong> {activity.teacherName} |
            <strong> Курсов:</strong> {activity.courseCount} |
            <strong> Тестов:</strong> {activity.testCount}
          </li>
        ))}
      </ul>
      <h3>Подробные отчеты</h3>
      <ul className="list-group">
        {reports.map((report) => {
          const reportUser = users.find((u) => u.id === report.data.studentId || u.id === report.data.teacherId);
          return (
            <li key={report.id} className="list-group-item">
              <strong>Тип:</strong> {report.type === "student_performance" ? "Успеваемость студента" : "Активность преподавателя"} <br />
              <strong>Пользователь:</strong> {reportUser?.name || "Неизвестный"} <br />
              <strong>Данные:</strong> {JSON.stringify(report.data)} <br />
              <strong>Дата:</strong> {new Date(report.createdAt).toLocaleString()}
            </li>
          );
        })}
      </ul>
    </div>
  );
}

export default Reports;
